import { buildFrequencyBank } from "../../lib/frequencyVocab";
import WORDS from "../vocab/itWords";

const cap = (s) => s.charAt(0).toUpperCase() + s.slice(1);

// Word Bank prompt formulas for buildFrequencyBank (generator is language-neutral).
const IT_FORMULAS = {
  recognitionPrompt: (w) => `'${cap(w)}' significa...`,
  recognitionNative: (w) => ({ en: `'${cap(w)}' means...` }),
  recognitionExplain: (w, g, noteEn) => ({
    en: `'${cap(w)}' means ${g}.${noteEn}`,
    es: `'${cap(w)}' significa ${g}.`,
  }),
  productionPrompt: (g) => `Come si dice '${g}' in italiano?`,
  productionNative: (g) => ({ en: `How do you say '${g}' in Italian?` }),
  productionExplain: (w, g, noteEn) => ({
    en: `'${g}' is '${w}'.${noteEn}`,
    es: `'${g}' se dice '${w}'.`,
  }),
};

